import{bQ as a,aL as e,u as r,G as d}from"./chunks/framework.D06dwy5q.js";const n=JSON.parse('{"title":"微服务演进","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/10-微服务演进.md","filePath":"00.互联网与架构基础/10-微服务演进.md","lastUpdated":null}'),A={name:"00.互联网与架构基础/10-微服务演进.md"};function o(E,t,p,i,l,h){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="微服务演进" tabindex="-1">微服务演进 <a class="header-anchor" href="#微服务演进" aria-label="Permalink to &quot;微服务演进&quot;">​</a></h1><p>很多系统一开始都是一个大应用。登录、用户、订单、报表、后台管理、定时任务都在同一个代码仓库、同一个进程里。这样的单体应用并不低级，早期反而很清楚：部署一个包，日志看一处，数据库也在一起。</p><p>业务和团队变大以后，单体会慢慢变重。改一个小功能要带上整包发布，模块之间互相引用，启动时间变长，某个慢接口可能把整个应用拖住。微服务就是从这些问题里拆出来的。</p><h2 id="一、一个大应用" tabindex="-1">一、一个大应用 <a class="header-anchor" href="#一、一个大应用" aria-label="Permalink to &quot;一、一个大应用&quot;">​</a></h2><p>单体应用大概长这样：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20Browser%5B%22%E6%B5%8F%E8%A7%88%E5%99%A8%22%5D%0A%20%20App%5B%22%E4%B8%80%E4%B8%AA%E5%90%8E%E7%AB%AF%E5%BA%94%E7%94%A8%22%5D%0A%20%20Module1%5B%22%E7%94%A8%E6%88%B7%E6%A8%A1%E5%9D%97%22%5D%0A%20%20Module2%5B%22%E8%AE%A2%E5%8D%95%E6%A8%A1%E5%9D%97%22%5D%0A%20%20Module3%5B%22%E6%8A%A5%E8%A1%A8%E6%A8%A1%E5%9D%97%22%5D%0A%20%20DB%5B%22%E5%90%8C%E4%B8%80%E4%B8%AA%E6%95%B0%E6%8D%AE%E5%BA%93%22%5D%0A%0A%20%20Browser%20--%3E%20App%0A%20%20App%20--%3E%20Module1%0A%20%20App%20--%3E%20Module2%0A%20%20App%20--%3E%20Module3%0A%20%20App%20--%3E%20DB%0A"></div><p>它适合早期系统。代码在一起，事务好处理，部署路径短，排查时也容易找到日志。</p><p>单体变难维护时，常见现象是：改一个模块需要理解很多无关代码，发布窗口越来越长，测试范围越来越大，某个高耗时接口把整个进程的线程池打满。</p><h2 id="二、拆成多个服务" tabindex="-1">二、拆成多个服务 <a class="header-anchor" href="#二、拆成多个服务" aria-label="Permalink to &quot;二、拆成多个服务&quot;">​</a></h2><p>服务拆分就是把不同业务能力拆成独立服务。例如用户服务、订单服务、支付服务、消息服务、报表服务。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20Gateway%5B%22%E7%BD%91%E5%85%B3%22%5D%0A%20%20User%5B%22%E7%94%A8%E6%88%B7%E6%9C%8D%E5%8A%A1%22%5D%0A%20%20Order%5B%22%E8%AE%A2%E5%8D%95%E6%9C%8D%E5%8A%A1%22%5D%0A%20%20Pay%5B%22%E6%94%AF%E4%BB%98%E6%9C%8D%E5%8A%A1%22%5D%0A%20%20Report%5B%22%E6%8A%A5%E8%A1%A8%E6%9C%8D%E5%8A%A1%22%5D%0A%20%20DB1%5B%22%E7%94%A8%E6%88%B7%E5%BA%93%22%5D%0A%20%20DB2%5B%22%E8%AE%A2%E5%8D%95%E5%BA%93%22%5D%0A%20%20DB3%5B%22%E6%8A%A5%E8%A1%A8%E5%BA%93%22%5D%0A%0A%20%20Gateway%20--%3E%20User%0A%20%20Gateway%20--%3E%20Order%0A%20%20Gateway%20--%3E%20Pay%0A%20%20Gateway%20--%3E%20Report%0A%20%20User%20--%3E%20DB1%0A%20%20Order%20--%3E%20DB2%0A%20%20Report%20--%3E%20DB3%0A"></div><p>拆分后，每个服务可以独立开发、独立部署、独立扩容。订单服务压力高，可以只扩订单服务；报表服务慢，可以限制它的资源，不让它拖垮登录接口。</p><p>代价也会出现。原来一次进程内函数调用，现在变成网络调用；原来一个事务里的几张表，可能分散在多个服务和数据库；原来一份日志，现在要跨多个服务找同一个请求。</p><h2 id="三、服务怎么找到彼此" tabindex="-1">三、服务怎么找到彼此 <a class="header-anchor" href="#三、服务怎么找到彼此" aria-label="Permalink to &quot;三、服务怎么找到彼此&quot;">​</a></h2><p>服务拆开以后，服务之间要找到彼此。订单服务调用用户服务时，如果把某台机器 IP 写死在代码里，实例扩容、迁移、重启都会影响调用方。</p><p>服务发现解决的是“服务名到实例地址”的问题。服务启动后把自己的地址注册到注册中心，调用方通过服务名拿到可用实例。</p><p>常见对象：</p><table tabindex="0"><thead><tr><th>对象</th><th>含义</th></tr></thead><tbody><tr><td>服务名</td><td>例如 <code>user-service</code></td></tr><tr><td>实例</td><td>某个具体 IP 和端口</td></tr><tr><td>注册中心</td><td>保存服务名和实例列表</td></tr><tr><td>健康检查</td><td>判断实例是否还可用</td></tr></tbody></table><p>Nacos、Consul、Eureka、Kubernetes Service 都和服务发现有关。Kubernetes 里服务名通过 DNS 解析到 Service，再由 Service 转发到后端 Pod。</p><h2 id="四、配置放哪里" tabindex="-1">四、配置放哪里 <a class="header-anchor" href="#四、配置放哪里" aria-label="Permalink to &quot;四、配置放哪里&quot;">​</a></h2><p>服务变多以后，配置也会变多。数据库地址、Redis 地址、开关、限流阈值、第三方接口地址，如果散落在每台机器的文件里，修改和回滚都很麻烦。</p><p>配置中心把配置集中管理，服务启动或运行时从配置中心读取。Nacos、Apollo、Spring Cloud Config 都是常见方案。</p><p>配置中心方便统一管理，也会让配置变更影响很多服务。配置发布同样需要版本、灰度、回滚和审计。</p><h2 id="五、调用别拖垮一片" tabindex="-1">五、调用别拖垮一片 <a class="header-anchor" href="#五、调用别拖垮一片" aria-label="Permalink to &quot;五、调用别拖垮一片&quot;">​</a></h2><p>微服务里很容易出现连锁反应。一个下游服务慢，上游线程池被占满，再上游继续排队，最后用户看到的是整个系统变慢。</p><p>常见治理手段：</p><table tabindex="0"><thead><tr><th>问题</th><th>常见做法</th></tr></thead><tbody><tr><td>接口变更影响调用方</td><td>接口版本、契约文档、兼容字段</td></tr><tr><td>下游服务慢</td><td>超时、重试、熔断、限流</td></tr><tr><td>调用链太长</td><td>链路追踪、依赖梳理</td></tr><tr><td>错误难定位</td><td>trace id、统一错误码、结构化日志</td></tr></tbody></table><p>超时、限流和熔断用来防止局部故障扩散。没有这些保护时，一个慢服务可能把一串服务都拖慢。</p><h2 id="六、拆多大" tabindex="-1">六、拆多大 <a class="header-anchor" href="#六、拆多大" aria-label="Permalink to &quot;六、拆多大&quot;">​</a></h2><p>服务拆得太少，单体问题还在；拆得太碎，网络调用、发布数量、日志链路和数据一致性都会变复杂。</p><p>比较稳的拆分尺度通常来自业务边界和数据边界。能独立描述职责、独立维护数据、独立扩容和发布的部分，更适合拆成服务。</p><p>微服务把单体里的模块边界变成运行时边界。它解决了团队协作、独立发布和局部扩容的问题，也带来了服务发现、配置中心、接口治理、链路追踪和分布式数据一致性这些新问题。</p>',32)])])}const B=a(A,[["render",o]]);export{n as __pageData,B as default};
